import React, { useEffect } from 'react';
import Particles from '../components/Particles';
import Navbar from '../components/Navbar';
import CeoSection from '../components/CeoSection';
import ServiceCard from '../components/ServiceCard';
import GalleryItem from '../components/GalleryItem';
import ContactForm from '../components/ContactForm';
import Footer from '../components/Footer';
import ControlesTema from '../components/ControlesTema';
import Carrito from '../components/Carrito';
import Producto from '../components/Producto';
import { useTema } from '../context/TemaContext';

const Home = () => {
  const { colorFondo, tamañoLetra, colores } = useTema();

  const appStyle = {
    background: colores[colorFondo] || colores.oscuro,
    fontSize: tamañoLetra === 'medium' ? '16px' :
              tamañoLetra === 'pequeño' ? '12px' :
              tamañoLetra === 'grande' ? '20px' : '25px',
    minHeight: '100vh',
    transition: 'all 0.4s ease'
  };

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) entry.target.classList.add('visible');
        });
      },
      { threshold: 0.1 }
    );

    document.querySelectorAll('.servicio-card, .galeria-item, .ceo-card').forEach((el) => {
      el.classList.add('scroll-hidden');
      observer.observe(el);
    });

    const handleScroll = () => {
      const navbar = document.querySelector('.navbar');
      if (!navbar) return;
      if (window.scrollY > 50) navbar.classList.add('scrolled');
      else navbar.classList.remove('scrolled');
    };
    window.addEventListener('scroll', handleScroll);

    return () => {
      observer.disconnect();
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const servicios = [
    {
      icon: `${process.env.PUBLIC_URL}/imagenes/Red Team.png`,
      bg: `${process.env.PUBLIC_URL}/imagenes/red team fondo.png`,
      title: 'Red Team',
      desc: 'Simulación de ataques avanzados para identificar vulnerabilidades antes que los ciberdelincuentes.',
      features: ['Pentesting Avanzado', 'Ingeniería Social', 'Explotación de Vulnerabilidades'],
      link: '/ciberseguridad#red-team'
    },
    {
      icon: `${process.env.PUBLIC_URL}/imagenes/Blue Team.png`,
      bg: `${process.env.PUBLIC_URL}/imagenes/blue team fondo.png`,
      title: 'Blue Team',
      desc: 'Defensa proactiva y respuesta a incidentes para mantener tus sistemas seguros 24/7.',
      features: ['Monitoreo SOC', 'Respuesta a Incidentes', 'Forense Digital'],
      link: '/ciberseguridad#blue-team'
    },
    {
      icon: `${process.env.PUBLIC_URL}/imagenes/Purple team.png`,
      bg: `${process.env.PUBLIC_URL}/imagenes/purple team fondo.png`,
      title: 'Purple Team',
      desc: 'Colaboración entre Red y Blue Team para maximizar la efectividad de la seguridad.',
      features: ['Evaluación Continua', 'Mejora de Defensas', 'Simulacros de Ataque'],
      link: '/ciberseguridad#purple-team'
    },
    {
      icon: `${process.env.PUBLIC_URL}/imagenes/TI.png`,
      bg: `${process.env.PUBLIC_URL}/imagenes/TI fondo.png`,
      title: 'Consultoría TI',
      desc: 'Asesoramiento especializado en protección de activos digitales y cumplimiento normativo.',
      features: ['Auditoría de Seguridad', 'Cumplimiento ISO 27001', 'Gestión de Riesgos'],
      link: '/ciberseguridad#consultoria'
    }
  ];

  const galeria = [
    { img: `${process.env.PUBLIC_URL}/imagenes/Potosina.png`, icon: 'fa-industry', name: 'Cervecería Potosina', sector: 'Sector Industrial' },
    { img: `${process.env.PUBLIC_URL}/imagenes/alcaldia Potosina.png`, icon: 'fa-landmark', name: 'Alcaldía de Potosí', sector: 'Sector Gubernamental' },
    { img: `${process.env.PUBLIC_URL}/imagenes/Ferroviaria SRL.png`, icon: 'fa-train', name: 'Ferroviaria SRL', sector: 'Sector Transporte' },
    { img: `${process.env.PUBLIC_URL}/imagenes/Jesus de Nazareth.png`, icon: 'fa-graduation-cap', name: 'U.E. Jesús de Nazaret', sector: 'Sector Educativo' },
    { img: `${process.env.PUBLIC_URL}/imagenes/empresas Bolivianas.png`, icon: 'fa-flag', name: 'Empresas Bolivianas', sector: 'Sector Privado' },
    { img: `${process.env.PUBLIC_URL}/imagenes/empresas nacionales.png`, icon: 'fa-briefcase', name: 'Empresas Nacionales', sector: 'Sector Corporativo' }
  ];

  const productos = [
    { id: 1, nombre: 'Laptop Gaming', precio: 9500, imagen: '💻' },
    { id: 2, nombre: 'Celular Poco X10', precio: 6350, imagen: '📱' },
    { id: 3, nombre: 'Auriculares', precio: 180, imagen: '🎧' },
    { id: 4, nombre: 'Tablet', precio: 7560, imagen: '🎛' }
  ];

  return (
    <div style={appStyle}>
      <Particles />
      <Navbar />
      <section className="banner banner-ti">
        <div className="banner-content">
          <div className="banner-icon">
            <i className="fas fa-shield-virus"></i>
          </div>
          <h1>Bienvenido a BlackCat Cibersecurity</h1>
          <p className="typing-text">Protegemos tus datos y defendemos tu empresa contra amenazas digitales.</p>
          <div className="banner-stats">
            {[
              { num: '500+', label: 'Clientes Protegidos' },
              { num: '99.9%', label: 'Uptime Garantizado' },
              { num: '24/7', label: 'Monitoreo Continuo' }
            ].map((stat, i) => (
              <div className="stat" key={i}>
                <span className="stat-number">{stat.num}</span>
                <span className="stat-label">{stat.label}</span>
              </div>
            ))}
          </div>
          <a href="#servicios" className="btn btn-glow">
            <i className="fas fa-rocket"></i> Ver Servicios
          </a>
        </div>
        <div className="scroll-indicator">
          <div className="mouse"></div>
          <span>Scroll</span>
        </div>
      </section>

      <section id="empresa" className="empresa">
        <div className="container empresa-content">
          <div className="section-header">
            <i className="fas fa-globe"></i>
            <h2>Accede al portal de ciberseguridad</h2>
          </div>
          <p>Entra al portal oficial de la compañía para conocer más sobre nuestros servicios, proyectos y soluciones en seguridad digital.</p>
          <a href="/ciberseguridad" className="btn btn-secondary">
            <i className="fas fa-external-link-alt"></i> Ir al sitio de ciberseguridad
          </a>
        </div>
      </section>

      <section className="empresa" style={{ background: '#1a1a1a', padding: '40px 0' }}>
        <div className="container">
          <ControlesTema />
        </div>
      </section>

      <section className="empresa" style={{ background: '#1a1a1a', padding: '40px 0' }}>
        <div className="container">
          <h2 style={{ color: '#00ffff', textAlign: 'center', marginBottom: '30px', fontFamily: 'Rajdhani, sans-serif' }}>
            🛍️ Tienda de Productos
          </h2>
          <div className="container" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '30px' }}>
            <section className="productos-seccion">
              <h2 style={{ color: '#8a2be2', marginBottom: '20px' }}>Productos Disponibles</h2>
              <div className="productos-grid">
                {productos.map((p) => (
                  <Producto key={p.id} producto={p} />
                ))}
              </div>
            </section>
            <Carrito />
          </div>
        </div>
      </section>

      <CeoSection />

      <section id="servicios" className="servicios">
        <div className="container">
          <div className="section-header">
            <i className="fas fa-tools"></i>
            <h2>Nuestros Servicios</h2>
            <p>Soluciones integrales de ciberseguridad para proteger tu organización</p>
          </div>
          <div className="servicios-grid">
            {servicios.map((svc, i) => (
              <ServiceCard key={i} servicio={svc} />
            ))}
          </div>
        </div>
      </section>

      <section id="galeria" className="galeria">
        <div className="container">
          <div className="section-header">
            <i className="fas fa-building"></i>
            <h2>Empresas que confían en nosotros</h2>
            <p>Protegiendo a las principales organizaciones de Bolivia</p>
          </div>
          <div className="galeria-grid">
            {galeria.map((item, i) => (
              <GalleryItem key={i} item={item} />
            ))}
          </div>
        </div>
      </section>

      <ContactForm />
      <Footer />
    </div>
  );
};

export default Home;
